function sliderAdvantages() {
    var swiper = new Swiper('.advantages .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 24,
        breakpoints: {
            320: {
                slidesPerView: 1.2,
            },
            375: {
                slidesPerView: 1.3,
            },
            577: {
                slidesPerView: 1.5,
            },
            769: {
                slidesPerView: 2.1,
            },
            1401: {
                slidesPerView: 2,
            }
        }
    })
}

function sliderAdvantages2() {
    var swiper = new Swiper('.advantages2 .mySwiper', {
        slidesPerView: 1.2,
        spaceBetween: 24,
    })
}

function sliderProjects() {
    var swiper = new Swiper('.projects .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 24,
        navigation: {
            nextEl: ".projects .swiper-button-next",
            prevEl: ".projects .swiper-button-prev",
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
            },
            577: {
                slidesPerView: 1.3,
            },
            769: {
                slidesPerView: 2,
            },
        }
    })
}

function sliderVideo() {
    var swiper = new Swiper('.video-section .mySwiper', {
        slidesPerView: 4,
        spaceBetween: 24,
        navigation: {
            nextEl: ".video-section .swiper-button-next",
            prevEl: ".video-section .swiper-button-prev",
        },
        breakpoints: {
            320: {
                slidesPerView: 2,
                spaceBetween: 12,
            },
            577: {
                slidesPerView: 2,
                spaceBetween: 24,
            },
            993: {
                slidesPerView: 3,
                spaceBetween: 24,
            },
            1601: {
                slidesPerView: 4,
                spaceBetween: 24,
            },
        }
    })
}

$(document).ready(function () {
  sliderAdvantages();
  sliderAdvantages2();
  sliderProjects();
  sliderVideo();

    // Tabs
    $(".tab").click(function () {
        let path = $(this).attr("data-tab-path")
        $(this).siblings(".tab").removeClass("tab--active")
        $(this).addClass("tab--active")

        $(this).parents(".tabs-inner").find(".tab__content").removeClass("tab__content--active")
        $(this).parents(".tabs-inner").find(`.tab__content[data-content-path="${path}"]`).addClass("tab__content--active")
    })

    // Modal
    $("[data-modal]").click(function () {
        let modalId = $(this).attr("data-modal")

        openModal(modalId)
    })

    function openModal(modalId){
        $(`#${modalId}`).addClass("modal--active")
        $("body").addClass("fixed-body")
    }

    $(".modal").click(function () {
        closeModal()
    })

    $("._close-modal").click(function () {
        closeModal()
    })

    $(".modal__dialog").click(function (e) {
        e.stopPropagation()
    })

    function closeModal() {
        $('.modal--active video').each(function () {
            this.pause();
            this.currentTime = 0;
        });

        $('.modal').removeClass("modal--active")
        $("body").removeClass("fixed-body")
    }

})

// Animation
gsap.registerPlugin(ScrollTrigger);

// Main
document.querySelectorAll('.main__inner').forEach((elem) => {
    gsap.from(elem, {
        y: 100,
        opacity: 0,
        duration: 1.5,
        ease: "power2.out",
        scrollTrigger: {
            trigger: elem,
            start: "top 80%",
            toggleActions: "play none none none",
        }
    });
});

